import { workflow, trigger, node } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const waitNode = node({
  type: 'n8n-nodes-base.wait',
  version: 1.1,
  config: {
    name: 'Wait 1 Second',
    parameters: {
      resume: 'timeInterval',
      amount: 1,
      unit: 'seconds'
    }
  }
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'running state test',
    parameters: {
      assignments: {
        assignments: []
      },
      options: {}
    }
  }
});

export default workflow('running-state-test', 'Running State Test')
  .add(manualTrigger)
  .to(waitNode)
  .to(setNode);
